// Aggregate all health check results
const uptimeResult = $('🌐 Check Site Uptime').first();
const pluginResult = $('🔌 Check Plugin Updates').first();
const postStatsResult = $('📊 Check Post Stats').first();
const recentPostsResult = $('📝 Fetch Recent Posts for Link Check').all();

// ── UPTIME ──────────────────────────────────────────────
const siteUp = uptimeResult.json.$response?.statusCode === 200 || 
               uptimeResult.json.statusCode === 200;
const uptimeStatus = siteUp ? '✅ ONLINE' : '🚨 DOWN';
const responseTime = uptimeResult.json.$response?.headers?.['x-response-time'] || 'N/A';

// ── PLUGINS ─────────────────────────────────────────────
const plugins = Array.isArray(pluginResult.json) ? pluginResult.json : [];
const pluginsNeedingUpdate = plugins.filter(p => p.update?.response?.id || p.new_version);
const activePlugins = plugins.filter(p => p.status === 'active');

// ── POST COUNT ──────────────────────────────────────────
const totalPosts = postStatsResult.json.$response?.headers?.['x-wp-total'] || 
                   postStatsResult.json.headers?.['x-wp-total'] || 'N/A';

// ── RECENT POST LINK CHECK ──────────────────────────────
const recentPosts = recentPostsResult.map(i => i.json);
const postsWithNoInternalLinks = recentPosts.filter(p => {
  const content = p.content?.rendered || '';
  const internalLinks = (content.match(/href="https?:\/\/clearstackstudio\.com[^"]*"/g) || []).length;
  return internalLinks === 0;
}).map(p => p.title?.rendered || 'Untitled');

// ── WORDPRESS CORE ──────────────────────────────────────
// Check if WP core update available via plugin endpoint response headers
const wpVersion = plugins[0]?.requires_wp || 'Unknown';

// ── HEALTH SCORE ────────────────────────────────────────
let score = 100;
if (!siteUp) score -= 50;
if (pluginsNeedingUpdate.length > 0) score -= (pluginsNeedingUpdate.length * 5);
if (postsWithNoInternalLinks.length > 3) score -= 10;
const healthGrade = score >= 90 ? 'A' : score >= 75 ? 'B' : score >= 60 ? 'C' : 'D';

const report = {
  timestamp: new Date().toISOString(),
  date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),

  uptime: {
    status: uptimeStatus,
    online: siteUp,
    response_time: responseTime
  },

  plugins: {
    total_active: activePlugins.length,
    updates_needed: pluginsNeedingUpdate.length,
    plugins_to_update: pluginsNeedingUpdate.map(p => ({
      name: p.name || p.plugin,
      current_version: p.version,
      new_version: p.new_version
    }))
  },

  content: {
    total_published_posts: totalPosts,
    recent_posts_checked: recentPosts.length,
    posts_missing_internal_links: postsWithNoInternalLinks.length,
    posts_missing_links_titles: postsWithNoInternalLinks.slice(0, 5)
  },

  health: {
    score: score,
    grade: healthGrade,
    alerts: [
      !siteUp ? '🚨 CRITICAL: Site appears to be DOWN' : null,
      pluginsNeedingUpdate.length > 0 ? `⚠️ ${pluginsNeedingUpdate.length} plugin(s) need updating` : null,
      pluginsNeedingUpdate.length > 3 ? '⚠️ Many outdated plugins = security risk' : null,
      postsWithNoInternalLinks.length > 3 ? `📝 ${postsWithNoInternalLinks.length} recent posts have no internal links` : null
    ].filter(Boolean)
  }
};

return [{ json: report }];

